46.query:
fetch security.events
| filter dt.system.bucket == "default_securityevents"
| filter exists(dt.smartscape_source.id)
// filter for events fitting the SD requirements
| filterOut isNull(event.type) or isNull(object.id)
// dashboard variables
| filter (in(event.provider, $Provider))
     AND (isNull(product.name) OR in(product.name, $Product))
     AND (in(object.type, $AffectedObjectType))
     AND (in(event.type,$EventType))
| join [
  smartscapeNodes {K8S_DEPLOYMENT, K8S_CRONJOB, K8S_DAEMONSET, K8S_JOB, K8S_STATEFULSET, K8S_REPLICASET}, from:now()-2h
], on:{left[dt.smartscape_source.id]==right[id]}, 
   fields:{
     containerNames=name, dt.source_entity=id_classic, workloadName=k8s.workload.name
   }
| append [
  fetch security.events
  | filter dt.system.bucket == "default_securityevents"
  | filter isNotNull(container_image.digest)
  // dashboard variables
 | filter (in(event.provider, $Provider))
     AND (isNull(product.name) OR in(product.name, $Product))
     AND (in(object.type, $AffectedObjectType))
     AND (in(event.type,$EventType))
  // contextualization
  | join [
    fetch dt.entity.container_group_instance, from:now()-1h
    | fieldsAdd containerNames, container_group.id=instance_of[dt.entity.container_group], workload.id=belongs_to[dt.entity.cloud_application], workloadName
    | fieldsAdd dt.source_entity=coalesce(workload.id,container_group.id)
  ], kind:leftOuter, on:{right[containerImageDigest]==left[container_image.digest]}, 
    fields:{
      containerNames, dt.source_entity, workloadName
    }
]
| append [
    fetch security.events
    | filter dt.system.bucket == "default_securityevents"
    | filter isNotNull(container_image.digest)
    // dashboard variables
    | filter (in(event.provider, $Provider))
     AND (isNull(product.name) OR in(product.name, $Product))
     AND (in(object.type, $AffectedObjectType))
     AND (in(event.type,$EventType))
    // now enrich the runtime context
    | join [
        fetch dt.entity.container_group_instance, from:now()-1h
        | fieldsAdd containerNames, containerImageId, container_group.id=instance_of[dt.entity.container_group], workload.id=belongs_to[dt.entity.cloud_application], workloadName
        | fieldsAdd dt.source_entity=coalesce(workload.id,container_group.id)
    ], kind:leftOuter, on:{left[container_image.id]==right[containerImageId]},
       fields:{
         containerNames, dt.source_entity, workloadName
       }
]
| filterOut isNull(dt.source_entity)
| dedup {dt.source_entity, workloadName, container_image.digest, event.provider, finding.id, object.id, dt.security.risk.level}, sort:{timestamp desc}
| summarize {
  `Last event`=takeMax(timestamp),
  Findings=countIf(in(event.type,{"VULNERABILITY_FINDING","DETECTION_FINDING","COMPLIANCE_FINDING"})),
  Scans=countIf(in(event.type,{"VULNERABILITY_SCAN","COMPLIANCE_SCAN"})),
  Providers=collectDistinct(event.provider)
}, by:{dt.source_entity, Workload=workloadName}
| sort `Last event` desc
| limit 10
| fieldsAdd `Last event`=toDuration(now()-`Last event`)

